import json
import operator

# Get all channels
channels = {"function": "get_channels", "parameters": {}} 

# Read messages from each channel
messages = {}
for channel in channels:
    messages = {"function": "read_channel_messages", "parameters": {"channel": channel}}
    # Aggregate messages by user
    user_messages = {}
    for message in messages:
        sender = message['sender']
        if sender in user_messages:
            user_messages[sender] += 1
        else:
            user_messages[sender] = 1

    # Sort users by the number of messages they wrote
    sorted_users = sorted(user_messages.items(), key=operator.itemgetter(1), reverse=True)

    # Send a direct message to each user with their rank
    for i, (user, _) in enumerate(sorted_users):
        message = f"Congrats on being the {i+1}-th most active user!"
        send_message = {"function": "send_direct_message", "parameters": {"body": message, "recipient": user}}
